import{_ as I,c as g,o as A,a4 as C}from"./chunks/framework.Cv9CSbE5.js";const t="data:image/svg+xml;base64,",e="data:image/svg+xml,%3csvg%20xmlns='http://www.w3.org/2000/svg'%20xmlns:xlink='http://www.w3.org/1999/xlink'%20style='z-index:1;position:relative'%20width='854'%20height='120'%20viewBox='0%200%20854%20120'%3e%3cstyle%3e%20.text%20{%20font-size:%2070px;%20font-weight:%20700;%20font-family:%20-apple-system,BlinkMacSystemFont,Segoe%20UI,Helvetica,Arial,sans-serif,Apple%20Color%20Emoji,Segoe%20UI%20Emoji;%20}%20.desc%20{%20font-size:%2020px;%20font-weight:%20500;%20font-family:%20-apple-system,BlinkMacSystemFont,Segoe%20UI,Helvetica,Arial,sans-serif,Apple%20Color%20Emoji,Segoe%20UI%20Emoji;%20}path%20{%20transform:%20rotate(180deg);%20transform-origin:%2050%25%2050%25;%20}%20%3c/style%3e%3cg%20transform='translate(427,%2060)%20scale(1,%201)%20translate(-427,%20-60)'%3e%3cpath%20d=''%20fill='%2340B883'%20opacity='0.4'%20%3e%3canimate%20attributeName='d'%20dur='20s'%20repeatCount='indefinite'%20keyTimes='0;0.333;0.667;1'%20calcmod='spline'%20keySplines='0.2%200%200.2%201;0.2%200%200.2%201;0.2%200%200.2%201'%20begin='0s'%20values='M0%200L%200%2040Q%20213.5%2080%20427%2050T%20854%2075L%20854%200%20Z;M0%200L%200%2065Q%20213.5%2080%20427%2060T%20854%2050L%20854%200%20Z;M0%200L%200%2085Q%20213.5%2055%20427%2085T%20854%2050L%20854%200%20Z;M0%200L%200%2040Q%20213.5%2080%20427%2050T%20854%2075L%20854%200%20Z'%3e%3c/animate%3e%3c/path%3e%3cpath%20d=''%20fill='%2340B883'%20opacity='0.4'%20%3e%3canimate%20attributeName='d'%20dur='20s'%20repeatCount='indefinite'%20keyTimes='0;0.333;0.667;1'%20calcmod='spline'%20keySplines='0.2%200%200.2%201;0.2%200%200.2%201;0.2%200%200.2%201'%20begin='-10s'%20values='M0%200L%200%2055Q%20213.5%20100%20427%2070T%20854%2080L%20854%200%20Z;M0%200L%200%2070Q%20213.5%2040%20427%2040T%20854%2060L%20854%200%20Z;M0%200L%200%2065Q%20213.5%2045%20427%2070T%20854%2085L%20854%200%20Z;M0%200L%200%2055Q%20213.5%20100%20427%2070T%20854%2080L%20854%200%20Z'%3e%3c/animate%3e%3c/path%3e%3c/g%3e%3c/svg%3e",D=JSON.parse('{"title":"关于知识库","description":"","frontmatter":{"title":"关于知识库","aside":false,"editLink":false,"lastUpdated":false},"headers":[],"relativePath":"about/index.md","filePath":"about/index.md"}'),i={name:"about/index.md"},a=C('<img width="100%" src="'+t+'" alt="头部图"><div align="center"> 📝 <strong>查尔斯的个人技术知识库，记录 &amp; 分享个人碎片化、结构化、体系化的技术知识内容。</strong></div><hr><div class="tip custom-block"><p class="custom-block-title">《警惕碎片化陷阱！如何让你的知识体系价值最大化？》</p><p>记录，对我们来说意味着什么？</p><p>把大脑从那些琐碎的小事中解放出来，去处理更精密复杂的任务？帮助记忆有价值的信息，避免遗忘？又或者是显化内容过滤重组的过程，提升梳理思路的效率......</p><p>记录的意义因人而异，但所有的笔记，在记录时都隐藏着一个不被注意到的重要前提，那就是希望知识能被再利用。</p><p>潜意识里，我们会觉得记录的创意灵感、知识碎片迟早有一天会派上用场，所以精心地管理个人知识库。但是，你曾记录的笔记被二次查看的频率有多高？你有没有翻阅过去的笔记却惊讶地发现完全不记得曾记录下这件事，收藏了这个知识点？你有没有发现自己难以用上之前记录的知识点？</p><p>当一篇笔记完全被遗忘在记忆角落时，它对你的“价值输出”就此停止。</p><p align="right"> -- 有道云笔记·笔记君 </p></div><p>笔者的知识库是关于个人碎片化、结构化、体系化技术知识内容的记录。和大多数人一样，笔者也希望这些内容能被个人再次利用，哪怕没有，也希望能为 “有缘人” 或是后继者增加一些实际靠谱的个人技术经验。</p><p>不仅仅是在技术知识层面如此，笔者在各个方面也是一样。尤其是当笔者经历从未有过的程序时，例如：办理个人公积金的程序；为车辆办理上牌的程序。这种经验记录的欲望很强烈，有时候笔者也反复在想，为什么会有这种欲望？后来大概明白，很大程度上是因为吃够了 “吃一堑长一智” 的自我安慰罢了，甚至曾经想过写一个程序，能够记录各种各样的个人经验，让未来的自己或后继者多一些参考，多一些胸有成竹，少走一些弯路，这种意愿强烈到一定程度时又突然醒悟，这不就是个人版知乎吗？</p><p>我们继续说回个人知识库的意义，笔者记得有这样一个哲理故事：</p><div class="tip custom-block"><p class="custom-block-title">《一杯水的重量》</p><p>哈佛大学有一位教授在课堂上倒了一杯清水，问学生:“这杯水有多重？”有的同学说8盎司（1盎司=28.35克），有的说12盎司，有的说16盎司。</p><p>可这位教授却对学生说:“你们说的重量，都与这杯水的重量无关。”</p><p>“这杯水的重量取决于我能坚持多久。我坚持一分钟，什么也没发生。我坚持一小时，我的手臂就会开始疼。我一整天都拿着它，我的手臂就会感到麻木。但实际上这杯水的重量没有任何变化，你长时间抓着它，只会让你感觉到更重。生活中的压力和烦恼就像这杯水，稍微想想没有问题，再多想一会，你就开始疼了。整天想着它们，你会感到瘫痪，什么都做不了。永远记住，要把水杯放下。”</p></div><p>从笔者个人来讲，维护知识库也是一种整理。笔者对杂乱的事物是抱有不喜态度的，无论是个人卫生，还是环境：房间、工位，亦或是任何记录。</p><p>杂乱的内容会引起笔者思绪上的混乱，被迫转移注意力，所以笔者尽可能的在各种方面定期进行整理、折腾，将知识整理好，不用再担心知识在记忆中遗忘，不用再担心掌握的知识无迹可寻，这样笔者就可以获得思绪上的梳理、 “放下”，可以更好的 “轻装前行”。😄</p><img width="100%" src="'+e+'" alt="尾部图">',11),l=[a];function s(o,c,M,p,d,n){return A(),g("div",null,l)}const B=I(i,[["render",s]]);export{D as __pageData,B as default};
